import React from "react";
import {
  Container,
  Sleeve,
  VinylRecord,
  VinylRecordMiddle,
  Circle,
} from "./styles";
import templeSmoke from "../../Assets/temple_smoke.png";

const RecordCover: React.FC = () => {
  return (
    <Container>
      <Sleeve src={templeSmoke}></Sleeve>
      <VinylRecord>
        <Circle diameter={30} />
        <Circle diameter={25} />
        <Circle diameter={20} />
        <Circle diameter={15} />
        <Circle diameter={10} />
        <Circle diameter={5} />
      </VinylRecord>
    </Container>
  );
};

export default RecordCover;
